import{_ as t}from"./chunks/apfpv.djmBxdWp.js";import{c as a,Q as s,j as i,m as n}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"APFPV Firmware from OpenIPC","description":"A new APFPV firmware type from the OpenIPC team for direct WiFi communication between VTX and ground station.","frontmatter":{"title":"APFPV Firmware from OpenIPC","date":"2025-05-30T00:00:00.000Z","description":"A new APFPV firmware type from the OpenIPC team for direct WiFi communication between VTX and ground station.","tags":["APFPV firmware","OpenIPC","RTL8812AU","RTL8733BU"],"head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/en/updates/posts/2025-05-30-apfpv"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/updates/posts/2025-05-30-apfpv"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/updates/posts/2025-05-30-apfpv"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/updates/posts/2025-05-30-apfpv"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/en/updates/posts/2025-05-30-apfpv"}],["meta",{"property":"og:title","content":"APFPV Firmware from OpenIPC"}],["meta",{"property":"og:description","content":"A new APFPV firmware type from the OpenIPC team for direct WiFi communication between VTX and ground station."}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-default.png"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:locale:alternate","content":"uk_UA"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-default.png"}],["meta",{"name":"twitter:title","content":"APFPV Firmware from OpenIPC"}],["meta",{"name":"twitter:description","content":"A new APFPV firmware type from the OpenIPC team for direct WiFi communication between VTX and ground station."}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://openfpv.com.ua/en/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Updates\\",\\"item\\":\\"https://openfpv.com.ua/en/updates\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"APFPV Firmware from OpenIPC\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"APFPV Firmware from OpenIPC\\",\\"description\\":\\"A new APFPV firmware type from the OpenIPC team for direct WiFi communication between VTX and ground station.\\",\\"inLanguage\\":\\"en-US\\",\\"url\\":\\"https://openfpv.com.ua/en/updates/posts/2025-05-30-apfpv\\",\\"image\\":\\"https://openfpv.com.ua/og-default.png\\",\\"dateModified\\":\\"2026-05-31T08:38:19.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"en/updates/posts/2025-05-30-apfpv.md","filePath":"en/updates/posts/2025-05-30-apfpv.md","lastUpdated":1780216699000}'),r={name:"en/updates/posts/2025-05-30-apfpv.md"};function p(o,e,l,h,d,c){return s(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="about-apfpv" tabindex="-1">About APFPV <a class="header-anchor" href="#about-apfpv" aria-label="Permalink to &quot;About APFPV&quot;">​</a></h1><p><strong>APFPV</strong> is a new firmware type from the <strong>OpenIPC</strong> team designed for experimenting with direct WiFi communication between VTX and the ground station.</p><p>This firmware is not a silver bullet or a major innovation — it is primarily aimed at beginners who find it difficult to configure <strong>WFB-NG</strong> and <strong>RubyFPV</strong> communication systems. It is also useful for those who need a link with low-speed vehicles such as cars, boats or even planes and quadcopters (without aerobatics). Signal latency depends on many factors and is typically <strong>40 to 70 ms</strong>.</p><img src="'+t+`" alt="apfpv" width="150px"><p>Another advantage of the firmware is <strong>no requirements for the base station WiFi chip</strong> — it can be any device. As a result, external devices from TP-Link, Ubiquiti and others can act as a base station, as they have good built-in antennas for reliable communication.</p><p>The VTX firmware includes two drivers for popular WiFi chips — <strong>RTL8812AU</strong> and <strong>RTL8733BU</strong> — ensuring maximum compatibility with various devices.</p><hr><h1 id="installing-the-firmware" tabindex="-1">Installing the firmware <a class="header-anchor" href="#installing-the-firmware" aria-label="Permalink to &quot;Installing the firmware&quot;">​</a></h1><p>Download the firmware archive and extract it:</p><p><a href="https://github.com/OpenIPC/builder/releases/download/latest/openipc.ssc338q-nor-apfpv.tgz" target="_blank" rel="noreferrer">https://github.com/OpenIPC/builder/releases/download/latest/openipc.ssc338q-nor-apfpv.tgz</a></p><p>Copy the files to <code>/tmp</code> using <strong>WinSCP</strong> (SCP protocol) or another method and install with the command:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sysupgrade</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -z</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --kernel=/tmp/uImage.ssc338q</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rootfs=/tmp/rootfs.squashfs.ssc338q</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>If your device is connected to the Internet, installation is even simpler — with a single command:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sysupgrade</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url=https://github.com/OpenIPC/builder/releases/download/latest/openipc.ssc338q-nor-apfpv.tgz</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>After installing the firmware, reboot the device. Then connect to the <strong>&quot;OpenIPC&quot;</strong> access point with the password <strong>&quot;12345678&quot;</strong>. Your device will receive a dynamic address from the <strong>192.168.0.0/24</strong> network.</p><div class="warning custom-block"><p class="custom-block-title">Important</p><p>By default, <strong>Majestic</strong> streams video via UDP/RTP to address <strong>192.168.0.10</strong>, and the firmware WebUI is available at <strong>192.168.0.1</strong> and opens in any browser.</p></div><hr><h1 id="viewing-video" tabindex="-1">Viewing video <a class="header-anchor" href="#viewing-video" aria-label="Permalink to &quot;Viewing video&quot;">​</a></h1><p>To view the video, you can:</p><ul><li>use the <strong>PixelPilot</strong> app on Android;</li><li>or on a Linux computer run the standard <strong>gstreamer</strong> command:</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gst-launch-1.0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> udpsrc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> port=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5600</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> !</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> application/x-rtp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> !</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rtph265depay</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> !</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> avdec_h265</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> !</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fpsdisplaysink</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Any other application that supports receiving an <strong>RTP stream over UDP</strong> on port <strong>5600</strong> can also be used.</p><hr><h1 id="changing-wifi-parameters" tabindex="-1">Changing WiFi parameters <a class="header-anchor" href="#changing-wifi-parameters" aria-label="Permalink to &quot;Changing WiFi parameters&quot;">​</a></h1><p>To change the access point name and password on the VTX, run the following commands via UART or SSH:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fw_setenv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wlanssid</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Drone</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fw_setenv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wlanpass</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openipcfpv</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div>`,26)])])}const k=a(r,[["render",p]]);export{u as __pageData,k as default};
